-- Seed data maintained directly as SQL.
-- Loaded by Supabase using supabase/config.toml [db.seed]. Edit this file directly when catalog values change.

ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, normalized_name = EXCLUDED.normalized_name, active = EXCLUDED.active;

ON CONFLICT (id) DO UPDATE SET crop_id = EXCLUDED.crop_id, name = EXCLUDED.name, normalized_name = EXCLUDED.normalized_name, active = EXCLUDED.active;

ON CONFLICT (crop_id, variety_id) DO UPDATE SET lifecycle_months = EXCLUDED.lifecycle_months, lifecycle_years = EXCLUDED.lifecycle_years, harvest_start_month = EXCLUDED.harvest_start_month, harvest_start_year = EXCLUDED.harvest_start_year, default_row_distance_m = EXCLUDED.default_row_distance_m, default_plant_distance_m = EXCLUDED.default_plant_distance_m, default_density_plants_ha = EXCLUDED.default_density_plants_ha, harvest_years = EXCLUDED.harvest_years, support_years = EXCLUDED.support_years, source_row = EXCLUDED.source_row, source_row_data = EXCLUDED.source_row_data;

ON CONFLICT (source_sheet, source_row) DO UPDATE SET crop_id = EXCLUDED.crop_id, variety_id = EXCLUDED.variety_id, age_years = EXCLUDED.age_years, stage_id = EXCLUDED.stage_id, potential_yield_kg_ha = EXCLUDED.potential_yield_kg_ha, default_density_plants_ha = EXCLUDED.default_density_plants_ha, density_factor = EXCLUDED.density_factor, water_factor = EXCLUDED.water_factor, source_row_data = EXCLUDED.source_row_data;

